import{_ as e,o as a,c as n,ag as o}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Đặc tả Bảo mật & Xác thực (Security & Auth Specs)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/04-bao-mat-xac-thuc.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/04-bao-mat-xac-thuc.md"}'),l={name:"99-tham-khao/archive/01-nen-tang-he-thong/04-bao-mat-xac-thuc.md"};function i(r,t,c,h,d,s){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="đac-ta-bao-mat-xac-thuc-security-auth-specs" tabindex="-1">Đặc tả Bảo mật &amp; Xác thực (Security &amp; Auth Specs) <a class="header-anchor" href="#đac-ta-bao-mat-xac-thuc-security-auth-specs" aria-label="Permalink to &quot;Đặc tả Bảo mật &amp; Xác thực (Security &amp; Auth Specs)&quot;">​</a></h1><p>Hệ thống Vivu Travel sử dụng <strong>Supabase Auth</strong> làm nền tảng quản lý danh tính cho Web Client và Admin Dashboard. Mobile App: Sprint sau (Phase 2).</p><blockquote><p><strong>Triển khai web:</strong> <a href="./../02-quan-ly-sprint/trang-thai-web">Trạng thái triển khai Web</a></p></blockquote><h2 id="_1-co-che-xac-thuc-authentication" tabindex="-1">1. Cơ chế Xác thực (Authentication) <a class="header-anchor" href="#_1-co-che-xac-thuc-authentication" aria-label="Permalink to &quot;1. Cơ chế Xác thực (Authentication)&quot;">​</a></h2><h3 id="luong-web-next-js-15-—-đa-trien-khai" tabindex="-1">Luồng Web (Next.js 15) — đã triển khai <a class="header-anchor" href="#luong-web-next-js-15-—-đa-trien-khai" aria-label="Permalink to &quot;Luồng Web (Next.js 15) — đã triển khai&quot;">​</a></h3><ul><li><strong>Cơ chế</strong>: Server-side Auth với <code>@supabase/ssr</code> + Server Actions (<code>src/actions/auth.actions.ts</code>).</li><li><strong>Callback OAuth / email</strong>: <code>GET /auth/callback</code> — đổi <code>code</code> lấy session, <code>AuthService.ensureUserProfile</code>.</li><li><strong>Hai phiên cookie</strong> (cùng lúc đăng nhập admin + khách nếu cần): <ul><li>Khách: <code>AUTH_COOKIES.PUBLIC</code></li><li>Admin: <code>AUTH_COOKIES.ADMIN</code></li></ul></li><li><strong>Middleware</strong> (<code>src/middleware.ts</code>): <ul><li>URL admin công khai: <code>/portal/*</code> (rewrite nội bộ từ <code>/admin/*</code>; truy cập trực tiếp <code>/admin</code> → 404).</li><li>Chưa đăng nhập vào route bảo vệ → redirect <code>/dang-nhap?returnTo=...</code></li><li>Admin: <code>/portal/login</code>, kiểm tra <code>Profile.role === ADMIN</code></li><li>Đã đăng nhập khách vào trang auth (<code>/dang-nhap</code>, <code>/dang-ky</code>, …) → redirect về trang chủ</li></ul></li></ul><h3 id="route-auth-khach-hang-tieng-viet" tabindex="-1">Route auth khách hàng (tiếng Việt) <a class="header-anchor" href="#route-auth-khach-hang-tieng-viet" aria-label="Permalink to &quot;Route auth khách hàng (tiếng Việt)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Route</th><th style="text-align:left;">Chức năng</th></tr></thead><tbody><tr><td style="text-align:left;"><code>/dang-nhap</code></td><td style="text-align:left;">Đăng nhập email / Google</td></tr><tr><td style="text-align:left;"><code>/dang-ky</code></td><td style="text-align:left;">Đăng ký</td></tr><tr><td style="text-align:left;"><code>/dang-ky/xac-nhan-email</code></td><td style="text-align:left;">Hướng dẫn xác nhận + gửi lại email</td></tr><tr><td style="text-align:left;"><code>/quen-mat-khau</code></td><td style="text-align:left;">Yêu cầu reset</td></tr><tr><td style="text-align:left;"><code>/dat-lai-mat-khau</code></td><td style="text-align:left;">Đặt mật khẩu mới (sau link email)</td></tr><tr><td style="text-align:left;"><code>/tai-khoan</code></td><td style="text-align:left;">Hồ sơ (đọc; sửa — chưa)</td></tr><tr><td style="text-align:left;"><code>/don-dat</code></td><td style="text-align:left;">Đơn của tôi (placeholder)</td></tr></tbody></table><h3 id="đang-nhap-google" tabindex="-1">Đăng nhập Google <a class="header-anchor" href="#đang-nhap-google" aria-label="Permalink to &quot;Đăng nhập Google&quot;">​</a></h3><ul><li><code>signInWithOAuth({ provider: &quot;google&quot; })</code> → redirect Supabase → Google → <code>/auth/callback</code>.</li><li>Cấu hình: Supabase Dashboard (Google provider) + Google Cloud redirect URI <code>https://&lt;project&gt;.supabase.co/auth/v1/callback</code>.</li><li>Branding consent screen: cấu hình trên <strong>Google Cloud OAuth consent screen</strong> (tên app Vivu).</li><li><strong>Gộp tài khoản:</strong> bật automatic linking cùng email trên Supabase nếu user vừa đăng ký email vừa đăng nhập Google.</li></ul><h3 id="email" tabindex="-1">Email <a class="header-anchor" href="#email" aria-label="Permalink to &quot;Email&quot;">​</a></h3><ul><li>Xác nhận đăng ký, reset mật khẩu: <strong>Supabase Auth SMTP</strong> + template HTML trong <code>travel-web/supabase/templates/</code>.</li><li>Không gửi mail đặt chỗ từ Next.js (Sprint 4).</li></ul><h3 id="luong-mobile-app-expo-—-planned" tabindex="-1">Luồng Mobile App (Expo) — Planned <a class="header-anchor" href="#luong-mobile-app-expo-—-planned" aria-label="Permalink to &quot;Luồng Mobile App (Expo) — Planned&quot;">​</a></h3><ul><li>JWT lưu tại <code>SecureStore</code>; refresh qua Supabase SDK.</li></ul><h2 id="_2-phan-quyen-role-based-access-control-rbac" tabindex="-1">2. Phân quyền (Role-Based Access Control - RBAC) <a class="header-anchor" href="#_2-phan-quyen-role-based-access-control-rbac" aria-label="Permalink to &quot;2. Phân quyền (Role-Based Access Control - RBAC)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Role</th><th style="text-align:left;">Quyền hạn</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>ADMIN</strong></td><td style="text-align:left;">Toàn quyền cấu hình hệ thống, quản lý nội dung, xem đơn hàng.</td></tr><tr><td style="text-align:left;"><strong>SUPPLIER</strong></td><td style="text-align:left;">(Sprint sau) Quản lý sản phẩm và đơn hàng của riêng mình.</td></tr><tr><td style="text-align:left;"><strong>USER</strong></td><td style="text-align:left;">Tìm kiếm tour, đặt chỗ (khi Sprint 4), quản lý lịch sử cá nhân.</td></tr></tbody></table><h2 id="_3-chinh-sach-bao-mat-du-lieu" tabindex="-1">3. Chính sách Bảo mật Dữ liệu <a class="header-anchor" href="#_3-chinh-sach-bao-mat-du-lieu" aria-label="Permalink to &quot;3. Chính sách Bảo mật Dữ liệu&quot;">​</a></h2><h3 id="row-level-security-rls-supabase" tabindex="-1">Row Level Security (RLS) - Supabase <a class="header-anchor" href="#row-level-security-rls-supabase" aria-label="Permalink to &quot;Row Level Security (RLS) - Supabase&quot;">​</a></h3><ul><li><strong>Mục tiêu</strong> (cần kiểm tra bật trên Dashboard): Destination/Tour public read; Booking theo <code>auth.uid()</code>; Profile chỉ owner sửa.</li><li><strong>Thực tế web:</strong> phần lớn mutation qua <strong>Prisma + Server Actions</strong> với <code>requireAdmin()</code>, không chỉ dựa RLS.</li></ul><h3 id="validation-backend-prisma" tabindex="-1">Validation Backend (Prisma) <a class="header-anchor" href="#validation-backend-prisma" aria-label="Permalink to &quot;Validation Backend (Prisma)&quot;">​</a></h3><ul><li><strong>Zod Schema</strong> tại Server Actions và API <code>api/v1/*</code>.</li></ul><hr><p><em>Tài liệu bảo mật v1.1 — đồng bộ web 17/05/2026</em></p>',23)])])}const p=e(l,[["render",i]]);export{g as __pageData,p as default};
